#[cfg(test)]
mod icon_tests {
    use super::*;

    #[test]
    fn test_icon_all_fields_serialize() {
        let icon = Icon {
            src: Some("https://example.com/icon.png".into()),
            mime_type: Some("image/png".into()),
            sizes: Some("32x32".into()),
        };
        let json = serde_json::to_string(&icon).unwrap();
        assert!(json.contains(r#""src":"https://example.com/icon.png""#));
        assert!(json.contains(r#""mimeType":"image/png""#));
        assert!(json.contains(r#""sizes":"32x32""#));
    }

    #[test]
    fn test_icon_partial_fields_serialize() {
        let icon = Icon {
            src: Some("https://example.com/icon.svg".into()),
            mime_type: None,
            sizes: None,
        };
        let json = serde_json::to_string(&icon).unwrap();
        assert!(json.contains(r#""src""#));
        assert!(!json.contains("mimeType"));
        assert!(!json.contains("sizes"));
    }

    #[test]
    fn test_icon_deserialize_partial() {
        let json = r#"{"src":"data:image/png;base64,..."}"#;
        let icon: Icon = serde_json::from_str(json).unwrap();
        assert!(icon.src.is_some());
        assert!(icon.mime_type.is_none());
    }

    #[test]
    fn test_tool_without_icon_no_field() {
        let tool = Tool {
            name: "test".into(),
            icon: None,
            ..Default::default()
        };
        let json = serde_json::to_string(&tool).unwrap();
        assert!(!json.contains("icon"));
    }

    #[test]
    fn test_tool_with_icon_includes_field() {
        let tool = Tool {
            name: "test".into(),
            icon: Some(Icon {
                src: Some("icon.png".into()),
                ..Default::default()
            }),
            ..Default::default()
        };
        let json = serde_json::to_string(&tool).unwrap();
        assert!(json.contains("icon"));
    }

    #[test]
    fn test_data_uri_icon() {
        let icon = Icon {
            src: Some("data:image/svg+xml;base64,PHN2Zy...".into()),
            mime_type: Some("image/svg+xml".into()),
            sizes: None,
        };
        let json = serde_json::to_string(&icon).unwrap();
        let parsed: Icon = serde_json::from_str(&json).unwrap();
        assert_eq!(icon, parsed);
    }
}
